// 解析 LINE Event 並判斷是「選模式」還是「直接搜尋」
const input = $input.first().json;
// n8n webhook 將 POST body 放在 .body 下，但也可能直接是 input 本身
const body = input.body || input;
const event = body.events?.[0];

if (!event || event.type !== 'message' || event.message.type !== 'text') {
  return [];
}

const userId = event.source.userId;
const replyToken = event.replyToken;
const text = event.message.text.trim();

// 判斷是「模式選擇」或「直接搜尋」
const modeButtons = ['品名搜尋', '廠商搜尋', '加工類型搜尋'];

if (modeButtons.includes(text)) {
  // 回覆提示
  const modeMap = { '品名搜尋': '品名', '廠商搜尋': '廠商', '加工類型搜尋': '加工類型' };
  return [{
    json: {
      action: 'prompt',
      replyToken,
      searchMode: modeMap[text]
    }
  }];
}

// 檢查是否為「模式:關鍵字」格式
const match = text.match(/^(品名|廠商|加工類型)[:：\s]+(.+)$/i);
if (match) {
  return [{
    json: {
      action: 'search',
      replyToken,
      userId,
      searchMode: match[1],
      keyword: match[2].trim()
    }
  }];
}

// 預設顯示說明
return [{
  json: {
    action: 'help',
    replyToken
  }
}];

